package com.trademaster.ims.mobile.fulfillment.service;

import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.checkout.model.*;import com.trademaster.ims.mobile.checkout.repository.*;import com.trademaster.ims.mobile.fulfillment.dto.FulfillmentDtos.*;import com.trademaster.ims.mobile.fulfillment.model.*;import com.trademaster.ims.mobile.fulfillment.repository.*;import com.trademaster.ims.mobile.notifications.service.CustomerNotificationService;import com.trademaster.ims.mobile.payments.model.*;import com.trademaster.ims.mobile.payments.repository.*;import com.trademaster.ims.model.*;import com.trademaster.ims.repository.*;import jakarta.persistence.criteria.Predicate;import org.springframework.beans.factory.annotation.*;import org.springframework.data.domain.*;import org.springframework.data.jpa.domain.Specification;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.util.StringUtils;import java.math.*;import java.time.*;import java.util.*;

@Service @Transactional public class OrderFulfillmentService{
 private final CustomerOrderRepository orders;private final CustomerOrderItemRepository items;private final CustomerOrderStatusHistoryRepository orderHistory;private final OrderFulfillmentRepository fulfillments;private final FulfillmentStatusHistoryRepository fulfillmentHistory;private final DeliveryEventRepository deliveryEvents;private final CODCollectionRepository codCollections;private final InventoryRepository inventory;private final StockMovementRepository stockMovements;private final WarehouseRepository warehouses;private final CustomerPaymentRepository payments;private final PaymentStatusHistoryRepository paymentHistory;private final FinancialAccountRepository accounts;private final AccountLedgerEntryRepository ledgers;@Autowired(required=false)private CustomerNotificationService notifications;@Value("${techsmart.fulfillment.default-warehouse-id:0}")private long configuredWarehouse;
 public OrderFulfillmentService(CustomerOrderRepository orders,CustomerOrderItemRepository items,CustomerOrderStatusHistoryRepository orderHistory,OrderFulfillmentRepository fulfillments,FulfillmentStatusHistoryRepository fulfillmentHistory,DeliveryEventRepository deliveryEvents,CODCollectionRepository codCollections,InventoryRepository inventory,StockMovementRepository stockMovements,WarehouseRepository warehouses,CustomerPaymentRepository payments,PaymentStatusHistoryRepository paymentHistory,FinancialAccountRepository accounts,AccountLedgerEntryRepository ledgers){this.orders=orders;this.items=items;this.orderHistory=orderHistory;this.fulfillments=fulfillments;this.fulfillmentHistory=fulfillmentHistory;this.deliveryEvents=deliveryEvents;this.codCollections=codCollections;this.inventory=inventory;this.stockMovements=stockMovements;this.warehouses=warehouses;this.payments=payments;this.paymentHistory=paymentHistory;this.accounts=accounts;this.ledgers=ledgers;}
 @Transactional(readOnly=true)public FulfillmentPage list(String status,String orderNumber,String paymentStatus,String dateFrom,String dateTo,String deliveryPartner,Pageable pageable){Specification<OrderFulfillment>spec=(root,q,cb)->{List<Predicate>ps=new ArrayList<>();if(StringUtils.hasText(status))ps.add(cb.equal(root.get("status"),OrderFulfillment.FulfillmentStatus.valueOf(status.trim().toUpperCase())));if(StringUtils.hasText(orderNumber))ps.add(cb.like(cb.lower(root.get("orderNumber")),"%"+orderNumber.trim().toLowerCase()+"%"));if(StringUtils.hasText(deliveryPartner))ps.add(cb.like(cb.lower(root.get("deliveryPartner")),"%"+deliveryPartner.trim().toLowerCase()+"%"));return cb.and(ps.toArray(Predicate[]::new));};Page<OrderFulfillment>pg=fulfillments.findAll(spec,pageable);List<FulfillmentSummary>content=pg.getContent().stream().filter(f->!StringUtils.hasText(paymentStatus)||f.getOrder().getPaymentStatus().name().equalsIgnoreCase(paymentStatus)).map(this::summary).toList();return new FulfillmentPage(content,pg.getNumber(),pg.getSize(),pg.getTotalElements(),pg.getTotalPages(),pg.isFirst(),pg.isLast());}
 @Transactional(readOnly=true)public FulfillmentDetail adminDetail(String orderNumber){return detail(requiredFulfillment(orderNumber));}
 public FulfillmentDetail startProcessing(String n,TransitionRequest q,String actor){CustomerOrder o=orders.lockByOrderNumber(n).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));if(existingTerminal(o))throw err(HttpStatus.CONFLICT,"FULFILLMENT_NOT_ALLOWED","This order cannot be fulfilled.");if(!eligibleToStart(o))throw err(HttpStatus.CONFLICT,"ORDER_PAYMENT_NOT_COMPLETED","Order is not ready for fulfillment.");OrderFulfillment f=fulfillments.lockByOrderNumber(n).orElse(null);if(f!=null)return detail(f);f=new OrderFulfillment();f.setFulfillmentNumber(number());f.setOrder(o);f.setOrderNumber(o.getOrderNumber());f.setWarehouseId(resolveWarehouse(q==null?null:q.warehouseId()).getId());f.setCreatedBy(actor);f.setUpdatedBy(actor);f=fulfillments.saveAndFlush(f);transitionOrder(o,CustomerOrder.OrderStatus.PROCESSING,"Order processing started.");history(f,null,"PROCESSING",q,actor);event(f,DeliveryEvent.EventType.PROCESSING,"Order processing started",customerNote(q,"Your order is being prepared."),null,true,null);notify(o,"ORDER_PROCESSING");return detail(f);} 
 public FulfillmentDetail pack(String n,TransitionRequest q,String actor){OrderFulfillment f=locked(n);CustomerOrder o=orders.lockByOrderNumber(n).orElseThrow();if(f.getStatus()==OrderFulfillment.FulfillmentStatus.PACKED)return detail(f);require(f,OrderFulfillment.FulfillmentStatus.PROCESSING);deductStockOnce(f,q);f.setStatus(OrderFulfillment.FulfillmentStatus.PACKED);f.setPackedAt(Instant.now());f.setUpdatedBy(actor);fulfillments.save(f);transitionOrder(o,CustomerOrder.OrderStatus.PACKED,"Order packed for delivery.");history(f,"PROCESSING","PACKED",q,actor);event(f,DeliveryEvent.EventType.PACKED,"Order packed",customerNote(q,"Your order is packed and ready to ship."),null,true,null);notify(o,"ORDER_PACKED");return detail(f);} 
 public FulfillmentDetail ship(String n,TransitionRequest q,String actor){OrderFulfillment f=locked(n);CustomerOrder o=orders.lockByOrderNumber(n).orElseThrow();if(f.getStatus()==OrderFulfillment.FulfillmentStatus.SHIPPED)return detail(f);require(f,OrderFulfillment.FulfillmentStatus.PACKED);applyDelivery(f,q);f.setStatus(OrderFulfillment.FulfillmentStatus.SHIPPED);f.setShippedAt(Instant.now());f.setUpdatedBy(actor);fulfillments.save(f);transitionOrder(o,CustomerOrder.OrderStatus.SHIPPED,"Order shipped.");history(f,"PACKED","SHIPPED",q,actor);event(f,DeliveryEvent.EventType.SHIPPED,"Order shipped",customerNote(q,"Your order has been shipped."),null,true,null);notify(o,"ORDER_SHIPPED");return detail(f);} 
 public FulfillmentDetail outForDelivery(String n,TransitionRequest q,String actor){OrderFulfillment f=locked(n);CustomerOrder o=orders.lockByOrderNumber(n).orElseThrow();if(f.getStatus()==OrderFulfillment.FulfillmentStatus.OUT_FOR_DELIVERY)return detail(f);require(f,OrderFulfillment.FulfillmentStatus.SHIPPED);applyDelivery(f,q);f.setStatus(OrderFulfillment.FulfillmentStatus.OUT_FOR_DELIVERY);f.setOutForDeliveryAt(Instant.now());f.setUpdatedBy(actor);fulfillments.save(f);transitionOrder(o,CustomerOrder.OrderStatus.OUT_FOR_DELIVERY,"Order is out for delivery.");history(f,"SHIPPED","OUT_FOR_DELIVERY",q,actor);event(f,DeliveryEvent.EventType.OUT_FOR_DELIVERY,"Out for delivery",customerNote(q,"Your order is out for delivery."),null,true,null);notify(o,"ORDER_OUT_FOR_DELIVERY");return detail(f);} 
 public FulfillmentDetail deliver(String n,TransitionRequest q,String actor){OrderFulfillment f=locked(n);CustomerOrder o=orders.lockByOrderNumber(n).orElseThrow();if(f.getStatus()==OrderFulfillment.FulfillmentStatus.DELIVERED)return detail(f);require(f,OrderFulfillment.FulfillmentStatus.OUT_FOR_DELIVERY);CustomerPayment p=payments.findTopByOrderIdOrderByCreatedAtDesc(o.getId()).orElse(null);if(o.getPaymentStatus()==CustomerOrder.PaymentStatus.COD_PENDING||p!=null&&p.getPaymentStatus()==CustomerPayment.PaymentStatus.COD_PENDING){if(q==null||q.collectedAmount()==null)throw err(HttpStatus.CONFLICT,"COD_COLLECTION_REQUIRED","COD collection amount is required before delivery.");if(p==null)throw err(HttpStatus.CONFLICT,"COD_COLLECTION_REQUIRED","COD payment record is required before delivery.");BigDecimal expected=p.getAmount().setScale(2,RoundingMode.HALF_UP),got=q.collectedAmount().setScale(2,RoundingMode.HALF_UP);if(expected.compareTo(got)!=0){codRecord(o,p,f,got,CODCollection.Status.COLLECTION_MISMATCH,actor,"COD amount mismatch");throw err(HttpStatus.CONFLICT,"COD_AMOUNT_MISMATCH","Collected COD amount does not match the order total.");}postCod(o,p,f,got,actor);}else if(o.getPaymentStatus()!=CustomerOrder.PaymentStatus.PAID||o.getAccountingStatus()!=CustomerOrder.AccountingStatus.POSTED){throw err(HttpStatus.CONFLICT,"ORDER_PAYMENT_NOT_COMPLETED","Prepaid order must be paid and posted before delivery.");}applyDelivery(f,q);f.setStatus(OrderFulfillment.FulfillmentStatus.DELIVERED);f.setDeliveredAt(Instant.now());f.setActualDeliveryDate(LocalDate.now());f.setUpdatedBy(actor);fulfillments.save(f);transitionOrder(o,CustomerOrder.OrderStatus.DELIVERED,"Order delivered.");history(f,"OUT_FOR_DELIVERY","DELIVERED",q,actor);event(f,DeliveryEvent.EventType.DELIVERED,"Order delivered",customerNote(q,"Your order has been delivered."),null,true,null);notify(o,"ORDER_DELIVERED");return detail(f);} 
 public FulfillmentDetail addEvent(String n,DeliveryEventRequest q,String actor){OrderFulfillment f=locked(n);DeliveryEvent.EventType t;try{t=DeliveryEvent.EventType.valueOf(q.eventType().trim().toUpperCase());}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"DELIVERY_EVENT_INVALID","Unsupported delivery event type.");}event(f,t,q.title(),q.description(),q.location(),q.customerVisible()==null||q.customerVisible(),q.occurredAt());return detail(f);} 
 @Transactional(readOnly=true)public OrderTrackingResponse customerTracking(long account,String n){CustomerOrder o=orders.findByOrderNumberAndAccountId(n,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));OrderFulfillment f=fulfillments.findByOrder_Id(o.getId()).orElse(null);List<DeliveryEventItem>events=f==null?List.of():deliveryEvents.findByFulfillmentIdAndCustomerVisibleTrueOrderByOccurredAtAsc(f.getId()).stream().map(this::eventDto).toList();String fs=f==null?null:f.getStatus().name();String current=currentStep(o,fs);return new OrderTrackingResponse(o.getOrderNumber(),o.getStatus().name(),fs,o.getPaymentStatus().name(),codStatus(o),o.getDeliverySnapshot(),f==null?null:f.getEstimatedDeliveryDate(),f==null?null:f.getDeliveryPartner(),f==null?null:f.getTrackingNumber(),f==null?null:mask(f.getDeliveryContactPhone()),f==null?null:f.getDeliveredAt(),current,steps(o,f),events);} 
 private void deductStockOnce(OrderFulfillment f,TransitionRequest q){if(f.isStockDeducted())return;Warehouse w=resolveWarehouse(q==null?f.getWarehouseId():q.warehouseId()!=null?q.warehouseId():f.getWarehouseId());f.setWarehouseId(w.getId());String group="CUSTOMER_ORDER_FULFILLMENT:"+f.getOrderNumber();for(CustomerOrderItem i:items.findByOrderIdOrderByIdAsc(f.getOrder().getId())){String ref=group+":"+i.getId();if(stockMovements.existsByReferenceNoAndMovementType(ref,StockMovement.MovementType.CUSTOMER_ORDER_FULFILLMENT))continue;Inventory inv=inventory.findByProductIdAndWarehouseId(i.getProductId(),w.getId()).orElseThrow(()->err(HttpStatus.CONFLICT,"STOCK_NOT_AVAILABLE","An item is not available for packing."));int prev=inv.getQuantity()==null?0:inv.getQuantity();if(prev<i.getQuantity())throw err(HttpStatus.CONFLICT,"STOCK_NOT_AVAILABLE","An item is not available for packing.");inv.removeStock(i.getQuantity());inventory.save(inv);StockMovement m=new StockMovement();m.setCompanyId(inv.getCompanyId());m.setProductId(i.getProductId());m.setWarehouseId(w.getId());m.setMovementType(StockMovement.MovementType.CUSTOMER_ORDER_FULFILLMENT);m.setReferenceId(f.getOrder().getId());m.setReferenceNo(ref);m.setQuantity(-i.getQuantity());m.setPreviousStock(prev);m.setNewStock(inv.getQuantity());m.setNotes("Customer order fulfillment "+f.getOrderNumber());stockMovements.save(m);}f.setStockDeducted(true);f.setStockDeductedAt(Instant.now());f.setStockMovementReference(group);} 
 private void postCod(CustomerOrder o,CustomerPayment p,OrderFulfillment f,BigDecimal got,String actor){CODCollection c=codRecord(o,p,f,got,CODCollection.Status.CASH_COLLECTED,actor,"COD collected in full");if(p.getAccountingStatus()!=CustomerPayment.AccountingStatus.POSTED){String key="CUSTOMER_PAYMENT:"+p.getPaymentNumber();if(!payments.existsByPostingKey(key)){FinancialAccount a=accounts.findAll().stream().filter(x->x.getStatus()==FinancialAccount.AccountStatus.ACTIVE).findFirst().orElseThrow(()->err(HttpStatus.CONFLICT,"COD_RECONCILIATION_FAILED","No active posting account is configured."));BigDecimal before=a.getCurrentBalance()==null?BigDecimal.ZERO:a.getCurrentBalance(),after=before.add(p.getAmount());a.setCurrentBalance(after);accounts.save(a);AccountLedgerEntry e=new AccountLedgerEntry();e.setAccountId(a.getAccountId());e.setEntryType(AccountLedgerEntry.EntryType.PAYMENT_RECEIPT);e.setDirection(Payment.PaymentDirection.RECEIVE);e.setDebitAmount(p.getAmount());e.setCreditAmount(BigDecimal.ZERO);e.setBalanceBefore(before);e.setBalanceAfter(after);e.setReferenceId(o.getId());e.setVoucherNo(p.getPaymentNumber());e.setDescription("COD collected and reconciled for order "+o.getOrderNumber());e.setPostedAt(java.time.LocalDateTime.now());ledgers.save(e);p.setLedgerEntryId(e.getLedgerEntryId());p.setPostingKey(key);p.setPostedAt(Instant.now());}p.setAccountingStatus(CustomerPayment.AccountingStatus.POSTED);}paymentTransition(p,CustomerPayment.PaymentStatus.CASH_COLLECTED,"COD_COLLECTION","Cash collected at delivery.",actor);paymentTransition(p,CustomerPayment.PaymentStatus.RECONCILED,"COD_RECONCILED","COD payment reconciled.",actor);paymentTransition(p,CustomerPayment.PaymentStatus.PAID,"ACCOUNTING_POSTED","COD payment collected and posted.",actor);p.setPaidAt(Instant.now());payments.save(p);o.setPaymentStatus(CustomerOrder.PaymentStatus.PAID);o.setAccountingStatus(CustomerOrder.AccountingStatus.POSTED);orders.save(o);c.setStatus(CODCollection.Status.RECONCILED);c.setReconciliationReference("COD_RECONCILED:"+p.getPaymentNumber());codCollections.save(c);event(f,DeliveryEvent.EventType.COD_COLLECTED,"COD collected","Cash on Delivery amount was collected.",null,true,null);event(f,DeliveryEvent.EventType.COD_RECONCILED,"COD reconciled","Cash on Delivery payment was reconciled.",null,true,null);if(notifications!=null){notifications.create(o.getAccountId(),com.trademaster.ims.mobile.notifications.model.CustomerNotification.NotificationType.COD_PAYMENT_COLLECTED,Map.of("orderNumber",o.getOrderNumber(),"paymentNumber",p.getPaymentNumber(),"amount",money(p.getAmount())),"PAYMENT",p.getPaymentNumber(),com.trademaster.ims.mobile.notifications.model.CustomerNotification.ActionType.OPEN_PAYMENT,o.getOrderNumber(),"COD_COLLECTED:"+p.getPaymentNumber(),true);notifications.create(o.getAccountId(),com.trademaster.ims.mobile.notifications.model.CustomerNotification.NotificationType.COD_PAYMENT_RECONCILED,Map.of("orderNumber",o.getOrderNumber(),"paymentNumber",p.getPaymentNumber(),"amount",money(p.getAmount())),"PAYMENT",p.getPaymentNumber(),com.trademaster.ims.mobile.notifications.model.CustomerNotification.ActionType.OPEN_PAYMENT,o.getOrderNumber(),"COD_RECONCILED:"+p.getPaymentNumber(),true);}}
 private CODCollection codRecord(CustomerOrder o,CustomerPayment p,OrderFulfillment f,BigDecimal got,CODCollection.Status st,String actor,String note){CODCollection c=codCollections.findByOrderId(o.getId()).orElseGet(CODCollection::new);c.setOrderId(o.getId());c.setPaymentId(p.getId());c.setFulfillmentId(f.getId());c.setExpectedAmount(p.getAmount());c.setCollectedAmount(got);c.setStatus(st);c.setCollectedAt(Instant.now());c.setCollectedBy(actor);c.setNote(note);return codCollections.save(c);} 
 private void paymentTransition(CustomerPayment p,CustomerPayment.PaymentStatus next,String source,String note,String actor){if(p.getPaymentStatus()==next)return;CustomerPayment.PaymentStatus prev=p.getPaymentStatus();p.setPaymentStatus(next);PaymentStatusHistory h=new PaymentStatusHistory();h.setPaymentId(p.getId());h.setPreviousStatus(prev==null?null:prev.name());h.setNewStatus(next.name());h.setSource(source);h.setCustomerVisibleNote(note);h.setActorType(PaymentStatusHistory.ActorType.ADMIN);h.setActorReference(actor);paymentHistory.save(h);} 
 private boolean eligibleToStart(CustomerOrder o){if(o.getStatus()!=CustomerOrder.OrderStatus.CONFIRMED)return false;if(o.getPaymentStatus()==CustomerOrder.PaymentStatus.COD_PENDING)return true;return o.getPaymentStatus()==CustomerOrder.PaymentStatus.PAID&&o.getAccountingStatus()==CustomerOrder.AccountingStatus.POSTED;}private boolean existingTerminal(CustomerOrder o){return Set.of(CustomerOrder.OrderStatus.CANCELLED,CustomerOrder.OrderStatus.RETURNED,CustomerOrder.OrderStatus.REFUNDED,CustomerOrder.OrderStatus.DELIVERED).contains(o.getStatus());}
 private void require(OrderFulfillment f,OrderFulfillment.FulfillmentStatus expected){if(f.getStatus()!=expected)throw err(HttpStatus.CONFLICT,"FULFILLMENT_INVALID_TRANSITION","Fulfillment transition is not allowed from the current state.");}
 private OrderFulfillment locked(String n){return fulfillments.lockByOrderNumber(n).orElseThrow(()->err(HttpStatus.NOT_FOUND,"FULFILLMENT_NOT_FOUND","Fulfillment was not found."));}private OrderFulfillment requiredFulfillment(String n){return fulfillments.findByOrderNumber(n).orElseThrow(()->err(HttpStatus.NOT_FOUND,"FULFILLMENT_NOT_FOUND","Fulfillment was not found."));}
 private Warehouse resolveWarehouse(Long requested){if(requested!=null&&requested>0)return warehouses.findById(requested).orElseThrow(()->err(HttpStatus.CONFLICT,"WAREHOUSE_NOT_AVAILABLE","Selected warehouse is not available."));if(configuredWarehouse>0)return warehouses.findById(configuredWarehouse).orElseThrow(()->err(HttpStatus.CONFLICT,"WAREHOUSE_NOT_AVAILABLE","Configured warehouse is not available."));List<Warehouse>active=warehouses.findByStatus("ACTIVE");if(!active.isEmpty())return active.get(0);return warehouses.findAll().stream().findFirst().orElseThrow(()->err(HttpStatus.CONFLICT,"WAREHOUSE_NOT_AVAILABLE","No warehouse is available for fulfillment."));}
 private void transitionOrder(CustomerOrder o,CustomerOrder.OrderStatus next,String note){if(o.getStatus()!=next){o.setStatus(next);orders.save(o);CustomerOrderStatusHistory h=new CustomerOrderStatusHistory();h.setOrderId(o.getId());h.setStatus(next.name());h.setCustomerNote(note);orderHistory.save(h);}}
 private void history(OrderFulfillment f,String prev,String next,TransitionRequest q,String actor){FulfillmentStatusHistory h=new FulfillmentStatusHistory();h.setFulfillmentId(f.getId());h.setPreviousStatus(prev);h.setNewStatus(next);h.setNote(q==null?null:clean(q.note()));h.setCustomerVisibleNote(customerNote(q,null));h.setActorType(FulfillmentStatusHistory.ActorType.ADMIN);h.setActorReference(actor);fulfillmentHistory.save(h);}private void event(OrderFulfillment f,DeliveryEvent.EventType t,String title,String desc,String loc,boolean visible,Instant when){DeliveryEvent e=new DeliveryEvent();e.setFulfillmentId(f.getId());e.setEventType(t);e.setTitle(title);e.setDescription(desc);e.setLocation(loc);e.setCustomerVisible(visible);e.setOccurredAt(when);deliveryEvents.save(e);}private void applyDelivery(OrderFulfillment f,TransitionRequest q){if(q==null)return;if(StringUtils.hasText(q.deliveryPartner()))f.setDeliveryPartner(clean(q.deliveryPartner()));if(StringUtils.hasText(q.trackingNumber()))f.setTrackingNumber(clean(q.trackingNumber()));if(q.estimatedDeliveryDate()!=null)f.setEstimatedDeliveryDate(q.estimatedDeliveryDate());if(StringUtils.hasText(q.deliveryContactName()))f.setDeliveryContactName(clean(q.deliveryContactName()));if(StringUtils.hasText(q.deliveryContactPhone()))f.setDeliveryContactPhone(clean(q.deliveryContactPhone()));if(StringUtils.hasText(q.note()))f.setDeliveryNote(clean(q.note()));}
 private FulfillmentSummary summary(OrderFulfillment f){CustomerOrder o=f.getOrder();return new FulfillmentSummary(o.getOrderNumber(),f.getFulfillmentNumber(),o.getStatus().name(),o.getPaymentStatus().name(),o.getAccountingStatus().name(),f.getStatus().name(),f.isStockDeducted(),f.getDeliveryPartner(),f.getTrackingNumber(),f.getEstimatedDeliveryDate(),f.getDeliveredAt(),o.getTotal());}private FulfillmentDetail detail(OrderFulfillment f){CustomerOrder o=f.getOrder();String cod=codCollections.findByOrderId(o.getId()).map(x->x.getStatus().name()).orElse(o.getPaymentStatus()==CustomerOrder.PaymentStatus.COD_PENDING?"COD_PENDING":null);return new FulfillmentDetail(o.getOrderNumber(),f.getFulfillmentNumber(),o.getStatus().name(),o.getPaymentStatus().name(),o.getAccountingStatus().name(),f.getStatus().name(),f.isStockDeducted(),f.getWarehouseId(),f.getDeliveryPartner(),f.getTrackingNumber(),f.getEstimatedDeliveryDate(),f.getPackedAt(),f.getShippedAt(),f.getOutForDeliveryAt(),f.getDeliveredAt(),cod,fulfillmentHistory.findByFulfillmentIdOrderByOccurredAtAsc(f.getId()).stream().map(h->new FulfillmentHistoryItem(h.getPreviousStatus(),h.getNewStatus(),h.getNote(),h.getCustomerVisibleNote(),h.getActorType().name(),h.getActorReference(),h.getOccurredAt())).toList(),deliveryEvents.findByFulfillmentIdOrderByOccurredAtAsc(f.getId()).stream().map(this::eventDto).toList());}
 private DeliveryEventItem eventDto(DeliveryEvent e){return new DeliveryEventItem(e.getEventType().name(),e.getTitle(),e.getDescription(),e.getLocation(),e.isCustomerVisible(),e.getOccurredAt());}private List<TrackingStep>steps(CustomerOrder o,OrderFulfillment f){Map<String,Instant>times=new HashMap<>();for(CustomerOrderStatusHistory h:orderHistory.findByOrderIdOrderByCreatedAtAsc(o.getId()))times.put(h.getStatus(),h.getCreatedAt());if(f!=null){if(f.getPackedAt()!=null)times.put("PACKED",f.getPackedAt());if(f.getShippedAt()!=null)times.put("SHIPPED",f.getShippedAt());if(f.getOutForDeliveryAt()!=null)times.put("OUT_FOR_DELIVERY",f.getOutForDeliveryAt());if(f.getDeliveredAt()!=null)times.put("DELIVERED",f.getDeliveredAt());}String current=currentStep(o,f==null?null:f.getStatus().name());List<String>keys=List.of("CONFIRMED","PROCESSING","PACKED","SHIPPED","OUT_FOR_DELIVERY","DELIVERED");int currentIdx=keys.indexOf(current);return keys.stream().map(k->{int i=keys.indexOf(k);String st=i<currentIdx||times.containsKey(k)?"COMPLETED":i==currentIdx?"CURRENT":"PENDING";return new TrackingStep(k,label(k),desc(k),st,times.get(k));}).toList();}
 private String currentStep(CustomerOrder o,String fs){if(o.getStatus()==CustomerOrder.OrderStatus.DELIVERED)return"DELIVERED";if(StringUtils.hasText(fs))return fs;return o.getStatus()==CustomerOrder.OrderStatus.CONFIRMED?"CONFIRMED":o.getStatus().name();}private String codStatus(CustomerOrder o){return codCollections.findByOrderId(o.getId()).map(x->x.getStatus().name()).orElse(o.getPaymentStatus()==CustomerOrder.PaymentStatus.COD_PENDING?"COD_PENDING":null);}private String label(String s){return Arrays.stream(s.split("_")).map(x->x.charAt(0)+x.substring(1).toLowerCase()).reduce((a,b)->a+" "+b).orElse(s);}private String desc(String k){return switch(k){case"CONFIRMED"->"Your order is confirmed.";case"PROCESSING"->"The order is being prepared.";case"PACKED"->"The order is packed.";case"SHIPPED"->"The order has shipped.";case"OUT_FOR_DELIVERY"->"The order is out for delivery.";case"DELIVERED"->"The order was delivered.";default->label(k);};}
 private void notify(CustomerOrder o,String code){if(notifications==null)return;var T=com.trademaster.ims.mobile.notifications.model.CustomerNotification.NotificationType.valueOf(code);notifications.create(o.getAccountId(),T,Map.of("orderNumber",o.getOrderNumber()),"ORDER",o.getOrderNumber(),com.trademaster.ims.mobile.notifications.model.CustomerNotification.ActionType.OPEN_ORDER,o.getOrderNumber(),code+":"+o.getOrderNumber(),code.endsWith("DELIVERED"));}
 private String number(){String n;do{n="FUL-"+LocalDate.now().toString().replace("-","")+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase();}while(fulfillments.existsByFulfillmentNumber(n));return n;}private String customerNote(TransitionRequest q,String fallback){return q!=null&&StringUtils.hasText(q.customerVisibleNote())?clean(q.customerVisibleNote()):fallback;}private String clean(String s){return s==null||s.isBlank()?null:s.replaceAll("<[^>]*>","").trim();}private String mask(String p){if(p==null||p.length()<5)return p;return p.substring(0,3)+"****"+p.substring(p.length()-2);}private String money(BigDecimal v){return (v==null?BigDecimal.ZERO:v).setScale(2,RoundingMode.HALF_UP).toPlainString();}private CustomerAuthException err(HttpStatus s,String c,String m){return new CustomerAuthException(s,c,m);} }